/**
 * Strategy-priority contract between the native row strategies, asserted through the {@code
 * nativeExecutionStrategy} explain metric. Both patterns clear the hash join's minimum-rows gate (4096), so before the
 * priority fix the batch hash join claimed even queries whose trailing legs are never consumed — enumerating the full
 * join where factorization collapses the legs to per-key counts. Parallel execution is disabled so the sequential
 * dispatch order is what gets exercised.
 */
public class LmdbNativeStrategyPriorityTest {

	private static final String EX = "http://example.com/";
	private static final int SUBJECTS = 4200;
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;
	private String previousParallel;

	@BeforeEach
	public void setUp() {
		previousParallel = System.getProperty(PARALLEL_FLAG);
		System.setProperty(PARALLEL_FLAG, "false");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			conn.begin();
			for (int i = 0; i < SUBJECTS; i++) {
				IRI subject = vf.createIRI(EX, "s" + i);
				conn.add(subject, p1, vf.createIRI(EX, "a" + i));
				conn.add(subject, p2, vf.createIRI(EX, "b" + i));
			}
			conn.commit();
		}
	}

	@AfterEach
	public void tearDown() {
		if (previousParallel == null) {
			System.clearProperty(PARALLEL_FLAG);
		} else {
			System.setProperty(PARALLEL_FLAG, previousParallel);
		}
		repository.shutDown();
	}

	@Test
	public void countingFactorizationOutranksBatchHashJoin() {
		// ?a and ?b are unprojected: both legs become COUNT branches, which replace enumeration with
		// per-distinct-key counting — asymptotically less work than the hash join's full enumeration
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE { ?s ex:p1 ?a . ?s ex:p2 ?b }";
		assertThat(strategy(query)).startsWith("chunkPipeline");
	}

	@Test
	public void unconsumedMidPlanPatternSinksToBranch() {
		// chain + leg: ?x is consumed by the pC pattern, so the trailing-suffix walk stops there and the
		// unconsumed pLeg pattern is stuck mid-prefix — unless the factorized order sinks it to the tail
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI type = vf.createIRI(EX, "T");
			IRI pLeg = vf.createIRI(EX, "pLeg");
			IRI pB = vf.createIRI(EX, "pB");
			IRI pC = vf.createIRI(EX, "pC");
			conn.begin();
			for (int i = 0; i < 10; i++) {
				IRI subject = vf.createIRI(EX, "t" + i);
				conn.add(subject, RDF.TYPE, type);
				for (int j = 0; j < 2 + (i % 2); j++) {
					conn.add(subject, pLeg, vf.createIRI(EX, "leg" + i + "_" + j));
				}
				for (int j = 0; j < 4; j++) {
					IRI hub = vf.createIRI(EX, "hub" + i + "_" + j);
					conn.add(subject, pB, hub);
					for (int k = 0; k < 500; k++) {
						conn.add(hub, pC, vf.createIRI(EX, "y" + i + "_" + j + "_" + k));
					}
				}
			}
			conn.commit();
		}
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE { ?s a ex:T . ?s ex:pLeg ?l . ?s ex:pB ?x . ?x ex:pC ?y }";
		assertThat(strategy(query))
				.startsWith("chunkPipeline")
				.contains("countBranches=2");
	}

	@Test
	public void valuesSeededStarStillFactorizes() {
		// a VALUES clause in the prefix must not disqualify factorization: only the tail branches need to
		// be plain patterns — the flat prefix runs through the ordinary cursor chain
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE { VALUES ?s { ex:s1 ex:s2 ex:s3 } ?s ex:p1 ?a . ?s ex:p2 ?b }";
		assertThat(strategy(query)).startsWith("factorizedRows");
	}

	@Test
	public void chunkPipelineEngagementIsVisibleInTelemetry() {
		// the chunk pipeline drives the all-pattern flat prefix; the explain metric must say so, or
		// silent fallbacks to the row chain would stay invisible
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE { ?s ex:p1 ?a . ?s ex:p2 ?b }";
		assertThat(strategy(query))
				.startsWith("chunkPipeline(")
				.contains("flat=")
				.contains("countBranches=");
	}

	@Test
	public void singlePatternSelectKeepsBatchScanPriority() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?a WHERE { ?s ex:p1 ?a }";

		assertThat(rows(query))
				.hasSize(SUBJECTS)
				.containsExactlyElementsOf(genericRows(query));
		assertThat(strategy(query))
				.as("a plain single-pattern SELECT must retain its existing batch scan")
				.isEqualTo("batch");
	}

	@Test
	public void valuesOnlySelectKeepsBatchPriority() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE { VALUES ?s { ex:s1 ex:s2 ex:s3 } }";

		assertThat(rows(query))
				.hasSize(3)
				.containsExactlyElementsOf(genericRows(query));
		assertThat(strategy(query))
				.as("a VALUES-only SELECT must retain its existing batch path")
				.isEqualTo("batch");
	}

	@Test
	public void fullyProjectedJoinKeepsBatchPriority() {
		// every leg is projected (all branches would be ENUM): factorization degenerates to memoized
		// enumeration, so the batch hash join keeps its priority until the chunk pipeline unifies costing
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?a ?b WHERE { ?s ex:p1 ?a . ?s ex:p2 ?b }";
		assertThat(strategy(query)).isEqualTo("batch");
	}

	private String strategy(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			GenericPlanNode plan = conn.prepareTupleQuery(query)
					.explain(Explanation.Level.Telemetry)
					.toGenericPlanNode();
			String strategy = findStrategy(plan);
			assertThat(strategy).as("expected a nativeExecutionStrategy metric in the explanation").isNotNull();
			return strategy;
		}
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			return QueryResults.asList(conn.prepareTupleQuery(query).evaluate())
					.stream()
					.map(Object::toString)
					.sorted()
					.toList();
		}
	}

	private List<String> genericRows(String query) {
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, "false");
			return rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
	}

	private static String findStrategy(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String value = node.getStringMetricActual("nativeExecutionStrategy");
		if (value != null) {
			return value;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String found = findStrategy(child);
				if (found != null) {
					return found;
				}
			}
		}
		return null;
	}
}
